import{_ as i,y as d,a as s,o as c,a2 as a,D as r,g as n,I as o}from"./chunks/framework.DCcmcJcL.js";const b=JSON.parse('{"title":"Company Credit (Pay By Credit)","description":"","frontmatter":{},"headers":[],"relativePath":"b2b-ecommerce-platform/company-credit.md","filePath":"b2b-ecommerce-platform/company-credit.md","lastUpdated":1782735915000}'),l={name:"b2b-ecommerce-platform/company-credit.md"};function m(p,e,g,h,y,u){const t=d("ImagePopup");return c(),s("div",null,[e[0]||(e[0]=a('<h1 id="company-credit-pay-by-credit" tabindex="-1">Company Credit (Pay By Credit) <a class="header-anchor" href="#company-credit-pay-by-credit" aria-label="Permalink to &quot;Company Credit (Pay By Credit)&quot;">​</a></h1><p>The Company Credit feature gives companies a buy-now-pay-later credit account. An administrator allocates a credit limit to a company; members can then place orders using the <strong>Pay By Credit</strong> payment method at checkout, drawing down the available credit. Every change to the balance is recorded in an audited credit ledger.</p><blockquote><p><strong>Note:</strong> Company Credit must first be enabled under <strong>Admin Panel → Configure → B2B Suite → Company Credit</strong>. See the <a href="./configuration.html">Configuration</a> guide.</p></blockquote><h2 id="company-credit-admin-end" tabindex="-1">Company Credit (Admin End) <a class="header-anchor" href="#company-credit-admin-end" aria-label="Permalink to &quot;Company Credit (Admin End)&quot;">​</a></h2><p>Navigate to <strong>Admin Panel → B2B → Company Credit</strong>. The page lists all companies along with their company name and email so you can manage credit per company.</p>',5)),r(t,{src:"/images/b2b-ecommerce-platform/credit-1.png",alt:"Company Credit List"}),e[1]||(e[1]=a('<h3 id="manage-credit" tabindex="-1">Manage Credit <a class="header-anchor" href="#manage-credit" aria-label="Permalink to &quot;Manage Credit&quot;">​</a></h3><p>Click <strong>Manage Credit</strong> for a company to open its credit page. This page shows the company details, the current credit position and the full credit history.</p><p><strong>Key figures:</strong></p><ul><li><strong>Credit Limit –</strong> The total credit allocated to the company.</li><li><strong>Outstanding Balance –</strong> The amount the company currently owes.</li><li><strong>Available Credit –</strong> The remaining credit the company can spend.</li></ul>',4)),r(t,{src:"/images/b2b-ecommerce-platform/credit-2.png",alt:"Manage Company Credit"}),e[2]||(e[2]=a('<h3 id="credit-settings" tabindex="-1">Credit Settings <a class="header-anchor" href="#credit-settings" aria-label="Permalink to &quot;Credit Settings&quot;">​</a></h3><p>Use <strong>Credit Settings</strong> to set or update the company&#39;s credit terms.</p><p><strong>1) Credit Limit –</strong> Enter the credit amount to allocate to the company.</p><p><strong>2) Status –</strong> Enable or disable the company&#39;s credit account.</p><p><strong>3) Allow orders to exceed the credit limit –</strong> When enabled, members can place orders even if they exceed the available credit.</p><p><strong>4) Comment –</strong> An optional note recorded with the change.</p><p>Click <strong>Save</strong> to apply the settings.</p><blockquote><p><strong>Note:</strong> If you lower a company&#39;s credit limit below its outstanding balance, the company is put <strong>over-limit</strong> — new purchases are blocked until the balance is paid down. A warning is shown and the change is recorded in the ledger.</p></blockquote>',8)),r(t,{src:"/images/b2b-ecommerce-platform/credit-4.png",alt:"Credit Settings"}),e[3]||(e[3]=a('<h3 id="reimburse-balance-record-a-payment" tabindex="-1">Reimburse Balance (Record a Payment) <a class="header-anchor" href="#reimburse-balance-record-a-payment" aria-label="Permalink to &quot;Reimburse Balance (Record a Payment)&quot;">​</a></h3><p>When a company pays down its balance (for example by bank transfer), record it using <strong>Reimburse Balance</strong>.</p><p><strong>1) Amount –</strong> The payment amount received.</p><p><strong>2) Comment –</strong> An optional reference or note.</p><p>Click <strong>Record Payment</strong> to apply the payment. This reduces the outstanding balance and frees up available credit.</p>',5)),r(t,{src:"/images/b2b-ecommerce-platform/credit-3.png",alt:"Reimburse Balance"}),e[4]||(e[4]=a('<h3 id="credit-history" tabindex="-1">Credit History <a class="header-anchor" href="#credit-history" aria-label="Permalink to &quot;Credit History&quot;">​</a></h3><p>The <strong>Credit History</strong> section is a full audited ledger of every change to the company&#39;s credit, including the operation, amount, resulting balance, related order/reference and date.</p><p><strong>Operations include:</strong></p><ul><li><strong>Credit Allocated</strong> – Credit added when a limit is first set.</li><li><strong>Limit Updated</strong> – The credit limit was changed.</li><li><strong>Order Purchase</strong> – Credit consumed by a Pay By Credit order.</li><li><strong>Payment Received</strong> – A reimbursement recorded against the balance.</li><li><strong>Order Refunded</strong> – Credit returned when an order is refunded.</li><li><strong>Order Reverted</strong> – Credit returned when an order is cancelled / reverted.</li></ul>',4)),r(t,{src:"/images/b2b-ecommerce-platform/credit-5.png",alt:"Credit History"}),e[5]||(e[5]=a('<h2 id="company-credit-storefront" tabindex="-1">Company Credit (Storefront) <a class="header-anchor" href="#company-credit-storefront" aria-label="Permalink to &quot;Company Credit (Storefront)&quot;">​</a></h2><p>Company members can view their credit account from <strong>My Account → Profile → Company Credit</strong>.</p><p>This page shows the company&#39;s <strong>Credit Limit</strong>, <strong>Outstanding Balance</strong> and <strong>Available Credit</strong>, along with the same credit history (transactions) recorded by the admin.</p><blockquote><p><strong>Note:</strong> The Company Credit link is hidden from the storefront account menu when the credit feature is disabled.</p></blockquote>',4)),r(t,{src:"/images/b2b-ecommerce-platform/credit-6.png",alt:"Storefront Company Credit"}),e[6]||(e[6]=n("h2",{id:"paying-with-company-credit-at-checkout",tabindex:"-1"},[o("Paying with Company Credit at Checkout "),n("a",{class:"header-anchor",href:"#paying-with-company-credit-at-checkout","aria-label":'Permalink to "Paying with Company Credit at Checkout"'},"​")],-1)),e[7]||(e[7]=n("p",null,[o("When a company has an active credit account, the "),n("strong",null,"Pay By Credit"),o(" payment method appears at checkout. Selecting it lets the company place the order against its available credit; the order amount is deducted from the available credit and recorded in the ledger as an "),n("em",null,"Order Purchase"),o(".")],-1)),e[8]||(e[8]=n("p",null,"If the order total exceeds the available credit (and the company is not allowed to exceed its limit), the order is blocked with a message asking the customer to reduce the cart or choose another payment method.",-1)),r(t,{src:"/images/b2b-ecommerce-platform/credit-7.png",alt:"Pay By Credit at Checkout"})])}const _=i(l,[["render",m]]);export{b as __pageData,_ as default};
